type HmacSha256 = Hmac<Sha256>;

/// Gateway service configuration.
#[derive(Clone, Debug, Eq, PartialEq)]
pub struct GatewayConfig {
    /// Address used by the binary listener.
    pub listen_addr: String,
    /// Deployment profile.
    pub environment: String,
    /// Optional `PostgreSQL` connection string.
    pub database_url: Option<String>,
    /// Optional Redis-compatible hot-state connection string.
    pub redis_url: Option<String>,
    /// Runtime hot-state backend profile used by routing, policy, and realtime views.
    pub hot_state_backend_profile: String,
    /// Runtime store profile used by the HTTP service.
    pub runtime_store_profile: String,
    /// Public browser-facing base URL.
    pub public_base_url: Option<String>,
    /// Explicit browser CORS origins.
    pub cors_allowed_origins: Vec<String>,
    /// Secret backend profile name.
    pub secret_backend_profile: String,
    /// Optional local file secret backend root.
    pub secret_backend_file_dir: Option<String>,
    /// Telemetry profile name.
    pub telemetry_profile: String,
    /// Whether browser session cookies must be marked Secure.
    pub session_cookie_secure: bool,
    /// Whether browser session cookies must be marked `HttpOnly`.
    pub session_cookie_http_only: bool,
    /// Browser session cookie `SameSite` policy.
    pub session_cookie_same_site: String,
    /// Maximum accepted request body bytes.
    pub max_body_bytes: usize,
    /// Maximum inbound request handling time in milliseconds.
    pub request_timeout_ms: u64,
    /// Runtime provider transport mode.
    pub provider_transport_mode: ProviderTransportMode,
    /// Dependency probe mode used by `/readyz`.
    pub dependency_probe_mode: DependencyProbeMode,
    /// Per-dependency readiness probe timeout in milliseconds.
    pub readiness_probe_timeout_ms: u64,
    /// Whether readiness requires a published config snapshot.
    pub require_published_snapshot: bool,
    /// Optional filesystem root used by file-backed export object storage.
    pub export_object_storage_dir: Option<String>,
    /// Optional external object storage HTTP writer.
    pub export_object_storage: Option<ExportObjectStorageHttpConfig>,
    /// Background worker scheduler mode for this process.
    pub background_worker_mode: BackgroundWorkerMode,
    /// Stable worker id used in worker health and audit evidence.
    pub worker_id: Option<String>,
    /// Shared background worker scheduler tick interval.
    pub worker_tick_interval_seconds: u64,
    /// Maximum notification outbox events delivered per tenant per tick.
    pub notification_worker_batch_limit: usize,
    /// Optional local single-user password login configuration.
    pub single_user_auth: Option<SingleUserAuthConfig>,
}

/// Dependency probing behavior for `/readyz`.
#[derive(Clone, Copy, Debug, Eq, PartialEq)]
pub enum DependencyProbeMode {
    /// Report configured dependency state without opening network connections.
    Configured,
    /// Open dependency connections and validate lightweight health state.
    Live,
}

impl DependencyProbeMode {
    const fn as_str(self) -> &'static str {
        match self {
            Self::Configured => "configured",
            Self::Live => "live",
        }
    }
}

/// Background worker scheduler mode.
#[derive(Clone, Copy, Debug, Eq, PartialEq)]
pub enum BackgroundWorkerMode {
    /// Run background workers in this process.
    Enabled,
    /// Do not run background workers in this process.
    Disabled,
}

/// Runtime provider execution mode.
#[derive(Clone, Copy, Debug, Eq, PartialEq)]
pub enum ProviderTransportMode {
    /// Use deterministic fake provider responses.
    Fake,
    /// Execute an opt-in live HTTP provider request and wrap the JSON response.
    Http,
}

/// External object storage writer configuration.
#[derive(Clone)]
pub struct ExportObjectStorageHttpConfig {
    /// HTTPS base URL that receives exported objects through PUT.
    pub base_url: String,
    /// Optional Authorization header value.
    pub authorization_header: Option<SecretString>,
    /// PUT request timeout in seconds.
    pub timeout_seconds: u64,
}

impl PartialEq for ExportObjectStorageHttpConfig {
    fn eq(&self, other: &Self) -> bool {
        self.base_url == other.base_url
            && self.timeout_seconds == other.timeout_seconds
            && self
                .authorization_header
                .as_ref()
                .map(secrecy::ExposeSecret::expose_secret)
                == other
                    .authorization_header
                    .as_ref()
                    .map(secrecy::ExposeSecret::expose_secret)
    }
}

impl Eq for ExportObjectStorageHttpConfig {}

impl std::fmt::Debug for ExportObjectStorageHttpConfig {
    fn fmt(&self, formatter: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        formatter
            .debug_struct("ExportObjectStorageHttpConfig")
            .field("base_url", &self.base_url)
            .field(
                "authorization_header",
                &self.authorization_header.as_ref().map(|_| "***"),
            )
            .field("timeout_seconds", &self.timeout_seconds)
            .finish()
    }
}

/// Local single-user password login configuration.
#[derive(Clone, Eq, PartialEq)]
pub struct SingleUserAuthConfig {
    /// Login username.
    pub username: String,
    /// Login password read from environment.
    pub password: String,
    /// Default tenant id.
    pub tenant_id: String,
    /// Default tenant display name.
    pub tenant_display_name: String,
    /// Default organization id.
    pub organization_id: String,
    /// Default organization display name.
    pub organization_display_name: String,
    /// Default project id.
    pub project_id: String,
    /// Default project display name.
    pub project_display_name: String,
    /// Default user id.
    pub user_id: String,
    /// Default user display name.
    pub user_display_name: String,
    /// Default user primary email.
    pub user_primary_email: Option<String>,
    /// Session lifetime in seconds.
    pub session_ttl_seconds: i64,
}

impl std::fmt::Debug for SingleUserAuthConfig {
    fn fmt(&self, formatter: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        formatter
            .debug_struct("SingleUserAuthConfig")
            .field("username", &self.username)
            .field("password", &"***")
            .field("tenant_id", &self.tenant_id)
            .field("tenant_display_name", &self.tenant_display_name)
            .field("organization_id", &self.organization_id)
            .field("organization_display_name", &self.organization_display_name)
            .field("project_id", &self.project_id)
            .field("project_display_name", &self.project_display_name)
            .field("user_id", &self.user_id)
            .field("user_display_name", &self.user_display_name)
            .field("user_primary_email", &self.user_primary_email)
            .field("session_ttl_seconds", &self.session_ttl_seconds)
            .finish()
    }
}

impl SingleUserAuthConfig {
    /// Builds a single-user config from required credentials and safe defaults.
    #[must_use]
    pub fn new(username: impl Into<String>, password: impl Into<String>) -> Self {
        let username = username.into();
        Self {
            user_display_name: username.clone(),
            username,
            password: password.into(),
            tenant_id: SINGLE_USER_TENANT_ID.to_owned(),
            tenant_display_name: "Single User Tenant".to_owned(),
            organization_id: SINGLE_USER_ORGANIZATION_ID.to_owned(),
            organization_display_name: "Single User Organization".to_owned(),
            project_id: SINGLE_USER_PROJECT_ID.to_owned(),
            project_display_name: "Default Project".to_owned(),
            user_id: SINGLE_USER_ID.to_owned(),
            user_primary_email: None,
            session_ttl_seconds: SINGLE_USER_SESSION_TTL_SECONDS,
        }
    }
}

impl Default for GatewayConfig {
    fn default() -> Self {
        Self {
            listen_addr: "127.0.0.1:8080".to_owned(),
            environment: "local".to_owned(),
            database_url: None,
            redis_url: None,
            hot_state_backend_profile: "memory".to_owned(),
            runtime_store_profile: "memory".to_owned(),
            public_base_url: None,
            cors_allowed_origins: Vec::new(),
            secret_backend_profile: "memory".to_owned(),
            secret_backend_file_dir: None,
            telemetry_profile: "disabled".to_owned(),
            session_cookie_secure: false,
            session_cookie_http_only: true,
            session_cookie_same_site: "lax".to_owned(),
            max_body_bytes: 1024 * 1024,
            request_timeout_ms: DEFAULT_REQUEST_TIMEOUT_MS,
            provider_transport_mode: ProviderTransportMode::Fake,
            dependency_probe_mode: DependencyProbeMode::Configured,
            readiness_probe_timeout_ms: 750,
            require_published_snapshot: false,
            export_object_storage_dir: None,
            export_object_storage: None,
            background_worker_mode: BackgroundWorkerMode::Enabled,
            worker_id: None,
            worker_tick_interval_seconds: DEFAULT_BACKGROUND_WORKER_TICK_SECONDS,
            notification_worker_batch_limit: DEFAULT_NOTIFICATION_WORKER_BATCH_LIMIT,
            single_user_auth: None,
        }
    }
}

impl GatewayConfig {
    /// Reads configuration from environment variables.
    #[must_use]
    pub fn from_env() -> Self {
        let mut config = Self::default();
        if let Ok(value) = std::env::var("STARWEAVER_GATEWAY_LISTEN_ADDR") {
            config.listen_addr = value;
        }
        if let Ok(value) = std::env::var("STARWEAVER_GATEWAY_ENV") {
            config.environment = value;
        }
        if let Ok(value) = std::env::var("STARWEAVER_GATEWAY_DATABASE_URL") {
            config.database_url = non_empty_env(&value);
        }
        if let Ok(value) = std::env::var("STARWEAVER_GATEWAY_REDIS_URL") {
            config.redis_url = non_empty_env(&value);
        }
        if let Ok(value) = std::env::var("STARWEAVER_GATEWAY_HOT_STATE_BACKEND")
            && let Some(value) = non_empty_env(&value)
        {
            config.hot_state_backend_profile = value.to_ascii_lowercase();
        }
        if let Ok(value) = std::env::var("STARWEAVER_GATEWAY_RUNTIME_STORE")
            && let Some(value) = non_empty_env(&value)
        {
            config.runtime_store_profile = value.to_ascii_lowercase();
        }
        if let Ok(value) = std::env::var("STARWEAVER_GATEWAY_PUBLIC_BASE_URL") {
            config.public_base_url = non_empty_env(&value);
        }
        if let Ok(value) = std::env::var("STARWEAVER_GATEWAY_CORS_ALLOWED_ORIGINS") {
            config.cors_allowed_origins = parse_csv_env(&value);
        }
        if let Ok(value) = std::env::var("STARWEAVER_GATEWAY_SECRET_BACKEND")
            && let Some(value) = non_empty_env(&value)
        {
            config.secret_backend_profile = value.to_ascii_lowercase();
        }
        if let Ok(value) = std::env::var("STARWEAVER_GATEWAY_SECRET_BACKEND_FILE_DIR") {
            config.secret_backend_file_dir = non_empty_env(&value);
        }
        if let Ok(value) = std::env::var("STARWEAVER_GATEWAY_TELEMETRY")
            && let Some(value) = non_empty_env(&value)
        {
            config.telemetry_profile = value;
        }
        if let Ok(value) = std::env::var("STARWEAVER_GATEWAY_SESSION_COOKIE_SECURE")
            && let Some(value) = parse_bool_env(&value)
        {
            config.session_cookie_secure = value;
        }
        if let Ok(value) = std::env::var("STARWEAVER_GATEWAY_SESSION_COOKIE_HTTP_ONLY")
            && let Some(value) = parse_bool_env(&value)
        {
            config.session_cookie_http_only = value;
        }
        if let Ok(value) = std::env::var("STARWEAVER_GATEWAY_SESSION_COOKIE_SAME_SITE")
            && let Some(value) = non_empty_env(&value)
        {
            config.session_cookie_same_site = value.to_ascii_lowercase();
        }
        if let Ok(value) = std::env::var("STARWEAVER_GATEWAY_MAX_BODY_BYTES")
            && let Ok(parsed) = value.parse::<usize>()
        {
            config.max_body_bytes = parsed;
        }
        if let Ok(value) = std::env::var("STARWEAVER_GATEWAY_REQUEST_TIMEOUT_MS")
            && let Ok(parsed) = value.parse::<u64>()
            && (MIN_REQUEST_TIMEOUT_MS..=MAX_REQUEST_TIMEOUT_MS).contains(&parsed)
        {
            config.request_timeout_ms = parsed;
        }
        if let Ok(value) = std::env::var("STARWEAVER_GATEWAY_PROVIDER_TRANSPORT")
            && let Some(mode) = parse_provider_transport_mode(&value)
        {
            config.provider_transport_mode = mode;
        }
        if let Ok(value) = std::env::var("STARWEAVER_GATEWAY_REQUIRE_SNAPSHOT") {
            config.require_published_snapshot = matches!(value.as_str(), "1" | "true" | "yes");
        }
        if let Ok(value) = std::env::var("STARWEAVER_GATEWAY_EXPORT_OBJECT_STORAGE_DIR") {
            config.export_object_storage_dir = non_empty_env(&value);
        }
        config.export_object_storage = export_object_storage_from_env();
        apply_background_worker_env(&mut config);
        config.dependency_probe_mode = default_dependency_probe_mode(&config);
        if let Ok(value) = std::env::var("STARWEAVER_GATEWAY_DEPENDENCY_PROBE_MODE")
            && let Some(mode) = parse_dependency_probe_mode(&value)
        {
            config.dependency_probe_mode = mode;
        }
        if let Ok(value) = std::env::var("STARWEAVER_GATEWAY_READINESS_PROBE_TIMEOUT_MS")
            && let Ok(parsed) = value.parse::<u64>()
            && (50..=5_000).contains(&parsed)
        {
            config.readiness_probe_timeout_ms = parsed;
        }
        config.single_user_auth = single_user_auth_from_env();
        config
    }
}

fn export_object_storage_from_env() -> Option<ExportObjectStorageHttpConfig> {
    let base_url = std::env::var("STARWEAVER_GATEWAY_EXPORT_OBJECT_STORAGE_URL")
        .ok()
        .and_then(|value| non_empty_env(&value))?;
    let authorization_header =
        std::env::var("STARWEAVER_GATEWAY_EXPORT_OBJECT_STORAGE_AUTHORIZATION")
            .ok()
            .and_then(|value| non_empty_env(&value))
            .map(SecretString::from);
    let timeout_seconds = std::env::var("STARWEAVER_GATEWAY_EXPORT_OBJECT_STORAGE_TIMEOUT_SECONDS")
        .ok()
        .and_then(|value| value.parse::<u64>().ok())
        .filter(|value| (1..=MAX_EXPORT_OBJECT_STORAGE_TIMEOUT_SECONDS).contains(value))
        .unwrap_or(DEFAULT_EXPORT_OBJECT_STORAGE_TIMEOUT_SECONDS);
    Some(ExportObjectStorageHttpConfig {
        base_url,
        authorization_header,
        timeout_seconds,
    })
}

fn apply_background_worker_env(config: &mut GatewayConfig) {
    if let Ok(value) = std::env::var("STARWEAVER_GATEWAY_BACKGROUND_WORKERS")
        && let Some(value) = parse_bool_env(&value)
    {
        config.background_worker_mode = if value {
            BackgroundWorkerMode::Enabled
        } else {
            BackgroundWorkerMode::Disabled
        };
    }
    if let Ok(value) = std::env::var("STARWEAVER_GATEWAY_WORKER_ID") {
        config.worker_id = parse_worker_id_env(&value);
    }
    if let Ok(value) = std::env::var("STARWEAVER_GATEWAY_WORKER_TICK_INTERVAL_SECONDS")
        && let Ok(parsed) = value.parse::<u64>()
        && (1..=3_600).contains(&parsed)
    {
        config.worker_tick_interval_seconds = parsed;
    }
    if let Ok(value) = std::env::var("STARWEAVER_GATEWAY_NOTIFICATION_WORKER_BATCH_LIMIT")
        && let Ok(parsed) = value.parse::<usize>()
        && (1..=1_000).contains(&parsed)
    {
        config.notification_worker_batch_limit = parsed;
    }
}

fn validate_gateway_config(config: &GatewayConfig) -> Result<()> {
    let diagnostics = production_profile_diagnostics(config);
    if diagnostics.is_empty() {
        Ok(())
    } else {
        Err(GatewayError::BadRequest {
            message: format!(
                "production profile is unsafe: {}",
                diagnostics
                    .iter()
                    .map(|diagnostic| diagnostic.code)
                    .collect::<Vec<_>>()
                    .join(",")
            ),
        })
    }
}

#[derive(Clone, Copy, Debug, Eq, PartialEq, Serialize)]
struct StartupDiagnostic {
    code: &'static str,
    message: &'static str,
}

fn production_profile_diagnostics(config: &GatewayConfig) -> Vec<StartupDiagnostic> {
    let mut diagnostics = Vec::new();
    push_runtime_store_diagnostics(config, &mut diagnostics);
    push_hot_state_backend_profile_diagnostics(config, &mut diagnostics);
    push_secret_backend_profile_diagnostics(config, &mut diagnostics);
    if !is_production_environment(&config.environment) {
        return diagnostics;
    }
    push_production_dependency_diagnostics(config, &mut diagnostics);
    push_production_browser_diagnostics(config, &mut diagnostics);
    diagnostics
}

fn push_runtime_store_diagnostics(
    config: &GatewayConfig,
    diagnostics: &mut Vec<StartupDiagnostic>,
) {
    match config.runtime_store_profile.as_str() {
        "postgres" if config.database_url.is_none() => {
            diagnostics.push(StartupDiagnostic {
                code: "postgres_runtime_store_database_url_required",
                message:
                    "STARWEAVER_GATEWAY_RUNTIME_STORE=postgres requires STARWEAVER_GATEWAY_DATABASE_URL",
            });
        }
        "memory" | "postgres" => {}
        _ => {
            diagnostics.push(StartupDiagnostic {
                code: "runtime_store_profile_unsupported",
                message: "HTTP runtime store profile must be memory or postgres",
            });
        }
    }
}

fn push_hot_state_backend_profile_diagnostics(
    config: &GatewayConfig,
    diagnostics: &mut Vec<StartupDiagnostic>,
) {
    match config.hot_state_backend_profile.as_str() {
        "memory" | "redis" => {}
        _ => {
            diagnostics.push(StartupDiagnostic {
                code: "hot_state_backend_profile_unsupported",
                message: "hot-state backend profile must be memory or redis",
            });
        }
    }
}

fn push_secret_backend_profile_diagnostics(
    config: &GatewayConfig,
    diagnostics: &mut Vec<StartupDiagnostic>,
) {
    match config.secret_backend_profile.as_str() {
        "memory" | "file" => {}
        _ => {
            diagnostics.push(StartupDiagnostic {
                code: "secret_backend_profile_unsupported",
                message: "secret backend profile must be memory or file",
            });
        }
    }
}

fn push_production_dependency_diagnostics(
    config: &GatewayConfig,
    diagnostics: &mut Vec<StartupDiagnostic>,
) {
    if config.database_url.is_none() {
        diagnostics.push(StartupDiagnostic {
            code: "database_url_required",
            message: "production requires STARWEAVER_GATEWAY_DATABASE_URL",
        });
    }
    if config.redis_url.is_none() {
        diagnostics.push(StartupDiagnostic {
            code: "redis_url_required",
            message: "production requires STARWEAVER_GATEWAY_REDIS_URL",
        });
    }
    if config.runtime_store_profile == "memory" {
        diagnostics.push(StartupDiagnostic {
            code: "durable_runtime_store_required",
            message: "production must not use the in-memory HTTP runtime store",
        });
    }
    if config.hot_state_backend_profile == "memory" {
        diagnostics.push(StartupDiagnostic {
            code: "durable_hot_state_backend_required",
            message: "production must not use the in-memory runtime hot-state backend",
        });
    }
    if config.secret_backend_profile == "memory" {
        diagnostics.push(StartupDiagnostic {
            code: "durable_secret_backend_required",
            message: "production must not use the in-memory secret backend",
        });
    }
    if config.secret_backend_profile == "file" && config.secret_backend_file_dir.is_none() {
        diagnostics.push(StartupDiagnostic {
            code: "secret_backend_file_dir_required",
            message: "file secret backend requires STARWEAVER_GATEWAY_SECRET_BACKEND_FILE_DIR",
        });
    }
    if config.telemetry_profile == "disabled" {
        diagnostics.push(StartupDiagnostic {
            code: "telemetry_required",
            message: "production requires telemetry to be enabled",
        });
    }
    if !config.require_published_snapshot {
        diagnostics.push(StartupDiagnostic {
            code: "published_snapshot_required",
            message: "production must require a published config snapshot",
        });
    }
    if config.dependency_probe_mode != DependencyProbeMode::Live {
        diagnostics.push(StartupDiagnostic {
            code: "live_dependency_probe_required",
            message: "production requires live dependency readiness probes",
        });
    }
    if config.max_body_bytes == 0 || config.max_body_bytes > 16 * 1024 * 1024 {
        diagnostics.push(StartupDiagnostic {
            code: "body_limit_invalid",
            message: "production requires a positive request body limit no larger than 16 MiB",
        });
    }
    if !(MIN_REQUEST_TIMEOUT_MS..=MAX_REQUEST_TIMEOUT_MS).contains(&config.request_timeout_ms) {
        diagnostics.push(StartupDiagnostic {
            code: "request_timeout_invalid",
            message: "production requires an inbound request timeout between 100 ms and 300000 ms",
        });
    }
    if config
        .export_object_storage
        .as_ref()
        .is_some_and(|object_storage| {
            safe_export_object_storage_base_url_for_config(config, &object_storage.base_url)
                .is_none()
        })
    {
        diagnostics.push(StartupDiagnostic {
            code: "export_object_storage_url_invalid",
            message: "production external object storage URL must be HTTPS and must not include credentials, query, or fragment",
        });
    }
}

fn push_production_browser_diagnostics(
    config: &GatewayConfig,
    diagnostics: &mut Vec<StartupDiagnostic>,
) {
    if !config
        .public_base_url
        .as_deref()
        .is_some_and(is_https_public_base_url)
    {
        diagnostics.push(StartupDiagnostic {
            code: "public_base_url_https_required",
            message: "production requires an HTTPS STARWEAVER_GATEWAY_PUBLIC_BASE_URL",
        });
    }
    if config.cors_allowed_origins.is_empty() {
        diagnostics.push(StartupDiagnostic {
            code: "cors_allowed_origins_required",
            message: "production requires explicit CORS allowed origins",
        });
    } else if !config
        .cors_allowed_origins
        .iter()
        .all(|origin| is_https_origin(origin))
    {
        diagnostics.push(StartupDiagnostic {
            code: "cors_allowed_origins_invalid",
            message: "production CORS origins must be HTTPS origins and must not be wildcard",
        });
    }
    if !config.session_cookie_secure {
        diagnostics.push(StartupDiagnostic {
            code: "secure_session_cookie_required",
            message: "production requires Secure browser session cookies",
        });
    }
    if !config.session_cookie_http_only {
        diagnostics.push(StartupDiagnostic {
            code: "http_only_session_cookie_required",
            message: "production requires HttpOnly browser session cookies",
        });
    }
    if !valid_same_site_policy(&config.session_cookie_same_site) {
        diagnostics.push(StartupDiagnostic {
            code: "session_cookie_same_site_invalid",
            message: "session cookie SameSite policy must be lax, strict, or none",
        });
    }
}

fn is_production_environment(environment: &str) -> bool {
    matches!(environment, "prod" | "production")
}

fn allows_local_callback_adapter(environment: &str) -> bool {
    matches!(environment, "local" | "test")
}

fn default_dependency_probe_mode(config: &GatewayConfig) -> DependencyProbeMode {
    if is_production_environment(&config.environment)
        || config.database_url.is_some()
        || config.redis_url.is_some()
    {
        DependencyProbeMode::Live
    } else {
        DependencyProbeMode::Configured
    }
}

fn parse_dependency_probe_mode(value: &str) -> Option<DependencyProbeMode> {
    match value.trim() {
        "configured" | "config" => Some(DependencyProbeMode::Configured),
        "live" => Some(DependencyProbeMode::Live),
        _ => None,
    }
}

fn parse_provider_transport_mode(value: &str) -> Option<ProviderTransportMode> {
    match value.trim().to_ascii_lowercase().as_str() {
        "fake" | "replay" | "synthetic" => Some(ProviderTransportMode::Fake),
        "http" | "live_http" | "live" => Some(ProviderTransportMode::Http),
        _ => None,
    }
}

fn non_empty_env(value: &str) -> Option<String> {
    let trimmed = value.trim();
    if trimmed.is_empty() {
        None
    } else {
        Some(trimmed.to_owned())
    }
}

fn parse_csv_env(value: &str) -> Vec<String> {
    value
        .split(',')
        .filter_map(non_empty_env)
        .collect::<Vec<_>>()
}

fn parse_bool_env(value: &str) -> Option<bool> {
    match value.trim().to_ascii_lowercase().as_str() {
        "1" | "true" | "yes" | "on" => Some(true),
        "0" | "false" | "no" | "off" => Some(false),
        _ => None,
    }
}

fn parse_worker_id_env(value: &str) -> Option<String> {
    non_empty_env(value).filter(|value| valid_worker_id(value))
}

fn valid_worker_id(value: &str) -> bool {
    !value.is_empty()
        && value.len() <= 128
        && value
            .bytes()
            .all(|byte| byte.is_ascii_alphanumeric() || matches!(byte, b'_' | b'-' | b'.' | b':'))
}

fn is_https_public_base_url(value: &str) -> bool {
    let Ok(parsed) = Url::parse(value) else {
        return false;
    };
    parsed.scheme() == "https" && parsed.host_str().is_some()
}

fn is_https_origin(value: &str) -> bool {
    if value.trim() == "*" {
        return false;
    }
    let Ok(parsed) = Url::parse(value) else {
        return false;
    };
    parsed.scheme() == "https"
        && parsed.host_str().is_some()
        && parsed.query().is_none()
        && parsed.fragment().is_none()
        && matches!(parsed.path(), "" | "/")
}

fn valid_same_site_policy(value: &str) -> bool {
    matches!(value, "lax" | "strict" | "none")
}

fn single_user_auth_from_env() -> Option<SingleUserAuthConfig> {
    let username = std::env::var("STARWEAVER_GATEWAY_SINGLE_USER_USERNAME")
        .ok()
        .and_then(|value| non_empty_env(&value));
    let password = std::env::var("STARWEAVER_GATEWAY_SINGLE_USER_PASSWORD")
        .ok()
        .and_then(|value| non_empty_env(&value));
    let (Some(username), Some(password)) = (username, password) else {
        return None;
    };
    let mut config = SingleUserAuthConfig::new(username, password);
    if let Ok(value) = std::env::var("STARWEAVER_GATEWAY_SINGLE_USER_EMAIL") {
        config.user_primary_email = non_empty_env(&value);
    }
    if let Ok(value) = std::env::var("STARWEAVER_GATEWAY_SINGLE_USER_DISPLAY_NAME")
        && let Some(value) = non_empty_env(&value)
    {
        config.user_display_name = value;
    }
    if let Ok(value) = std::env::var("STARWEAVER_GATEWAY_SINGLE_USER_SESSION_TTL_SECONDS")
        && let Ok(parsed) = value.parse::<i64>()
        && (300..=86_400).contains(&parsed)
    {
        config.session_ttl_seconds = parsed;
    }
    Some(config)
}

/// Gateway app state.
#[derive(Clone)]
pub struct AppState {
    config: GatewayConfig,
    store: InMemoryGatewayStore,
    route_hot_state: Arc<dyn RouteHotState>,
    runtime_policy_store: Arc<dyn RuntimePolicyRepository>,
    postgres_store: Option<PostgresGatewayStore>,
}

impl std::fmt::Debug for AppState {
    fn fmt(&self, formatter: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        formatter
            .debug_struct("AppState")
            .field("config", &self.config)
            .field("store", &self.store)
            .field("route_hot_state", &self.config.hot_state_backend_profile)
            .field(
                "runtime_policy_store",
                &self.config.hot_state_backend_profile,
            )
            .field("postgres_store", &self.postgres_store)
            .finish()
    }
}

impl AppState {
    /// Creates app state from config and in-memory foundation store.
    #[must_use]
    pub fn new(config: GatewayConfig, store: InMemoryGatewayStore) -> Self {
        let route_hot_state = Arc::new(store.clone());
        let runtime_policy_store = Arc::new(store.clone());
        Self {
            config,
            store,
            route_hot_state,
            runtime_policy_store,
            postgres_store: None,
        }
    }

    /// Creates app state with an explicit runtime policy hot-state backend.
    #[must_use]
    pub fn new_with_runtime_policy_store(
        config: GatewayConfig,
        store: InMemoryGatewayStore,
        runtime_policy_store: Arc<dyn RuntimePolicyRepository>,
    ) -> Self {
        let route_hot_state = Arc::new(store.clone());
        Self {
            config,
            store,
            route_hot_state,
            runtime_policy_store,
            postgres_store: None,
        }
    }

    /// Creates app state with explicit route and runtime policy hot-state backends.
    #[must_use]
    pub fn new_with_hot_state_backends(
        config: GatewayConfig,
        store: InMemoryGatewayStore,
        route_hot_state: Arc<dyn RouteHotState>,
        runtime_policy_store: Arc<dyn RuntimePolicyRepository>,
    ) -> Self {
        Self {
            config,
            store,
            route_hot_state,
            runtime_policy_store,
            postgres_store: None,
        }
    }

    /// Creates app state with an additional durable `PostgreSQL` store.
    #[must_use]
    pub fn new_with_postgres_store(
        config: GatewayConfig,
        store: InMemoryGatewayStore,
        postgres_store: PostgresGatewayStore,
    ) -> Self {
        let route_hot_state = Arc::new(store.clone());
        let runtime_policy_store = Arc::new(store.clone());
        Self {
            config,
            store,
            route_hot_state,
            runtime_policy_store,
            postgres_store: Some(postgres_store),
        }
    }

    /// Creates app state with durable `PostgreSQL` and runtime policy hot state.
    #[must_use]
    pub fn new_with_postgres_store_and_runtime_policy_store(
        config: GatewayConfig,
        store: InMemoryGatewayStore,
        postgres_store: PostgresGatewayStore,
        runtime_policy_store: Arc<dyn RuntimePolicyRepository>,
    ) -> Self {
        let route_hot_state = Arc::new(store.clone());
        Self {
            config,
            store,
            route_hot_state,
            runtime_policy_store,
            postgres_store: Some(postgres_store),
        }
    }

    /// Creates app state with durable `PostgreSQL` and explicit hot-state backends.
    #[must_use]
    pub fn new_with_postgres_store_and_hot_state_backends(
        config: GatewayConfig,
        store: InMemoryGatewayStore,
        postgres_store: PostgresGatewayStore,
        route_hot_state: Arc<dyn RouteHotState>,
        runtime_policy_store: Arc<dyn RuntimePolicyRepository>,
    ) -> Self {
        Self {
            config,
            store,
            route_hot_state,
            runtime_policy_store,
            postgres_store: Some(postgres_store),
        }
    }

    /// Returns the service configuration.
    #[must_use]
    pub const fn config(&self) -> &GatewayConfig {
        &self.config
    }

    /// Returns the foundation store.
    #[must_use]
    pub const fn store(&self) -> &InMemoryGatewayStore {
        &self.store
    }

    /// Returns the route hot-state backend.
    #[must_use]
    pub fn route_hot_state(&self) -> &dyn RouteHotState {
        self.route_hot_state.as_ref()
    }

    /// Returns the runtime policy hot-state backend.
    #[must_use]
    pub fn runtime_policy_store(&self) -> &dyn RuntimePolicyRepository {
        self.runtime_policy_store.as_ref()
    }

    /// Returns whether route decisions and attempts are bridged to `PostgreSQL`.
    #[must_use]
    pub const fn durable_route_evidence_enabled(&self) -> bool {
        self.postgres_store.is_some()
    }

    /// Returns whether authentication can read from durable `PostgreSQL`.
    #[must_use]
    pub const fn durable_auth_enabled(&self) -> bool {
        self.postgres_store.is_some()
    }
}

impl Default for AppState {
    fn default() -> Self {
        Self::new(GatewayConfig::default(), InMemoryGatewayStore::default())
    }
}

/// Builds the gateway router.
pub fn router(state: AppState) -> Router {
    let max_body_bytes = state.config.max_body_bytes;
    Router::new()
        .route("/healthz", get(healthz))
        .route("/readyz", get(readyz))
        .route("/version", get(version))
        .merge(gateway_api_routes(&state))
        .nest("/api", prefixed_gateway_api_routes(&state))
        .layer(DefaultBodyLimit::max(max_body_bytes))
        .layer(middleware::from_fn_with_state(
            state.clone(),
            request_timeout_middleware,
        ))
        .layer(middleware::from_fn(request_id_middleware))
        .with_state(state)
}

fn gateway_api_routes(state: &AppState) -> Router<AppState> {
    Router::new()
        .merge(model_routes(state))
        .merge(auth_routes())
        .merge(admin_routes(state))
}

fn prefixed_gateway_api_routes(state: &AppState) -> Router<AppState> {
    Router::new()
        .route("/openapi.json", get(openapi_json))
        .route("/system/healthz", get(healthz))
        .route("/system/readyz", get(readyz))
        .route("/system/version", get(version))
        .merge(gateway_api_routes(state))
        .fallback(api_not_found)
}

async fn openapi_json() -> Result<Json<Value>> {
    serde_json::from_str(GATEWAY_OPENAPI_JSON)
        .map(Json)
        .map_err(|error| GatewayError::Internal {
            message: format!("failed to parse embedded gateway OpenAPI document: {error}"),
        })
}

async fn api_not_found() -> GatewayError {
    GatewayError::NotFound {
        resource: "gateway API route".to_owned(),
    }
}

