#[derive(Clone, Debug, Deserialize)]
#[serde(untagged)]
enum OidcAudience {
    Single(String),
    Multiple(Vec<String>),
}

impl OidcAudience {
    fn contains(&self, value: &str) -> bool {
        match self {
            Self::Single(audience) => audience == value,
            Self::Multiple(audiences) => audiences.iter().any(|audience| audience == value),
        }
    }
}

