fn request_id_from_headers(headers: &HeaderMap) -> String {
    headers
        .get(REQUEST_ID_HEADER)
        .and_then(|value| value.to_str().ok())
        .filter(|value| is_safe_request_id(value))
        .map_or_else(|| new_prefixed_id("req"), ToOwned::to_owned)
}

fn bearer_token(headers: &HeaderMap) -> Result<&str> {
    let Some(value) = headers.get(header::AUTHORIZATION) else {
        return Err(GatewayError::Authentication);
    };
    let value = value.to_str().map_err(|_| GatewayError::Authentication)?;
    let Some((scheme, token)) = value.split_once(' ') else {
        return Err(GatewayError::Authentication);
    };
    let token = token.trim();
    if !scheme.eq_ignore_ascii_case("Bearer") || token.is_empty() {
        return Err(GatewayError::Authentication);
    }
    Ok(token)
}

fn optional_header(headers: &HeaderMap, name: &'static str) -> Result<Option<String>> {
    headers
        .get(name)
        .map(|value| {
            value
                .to_str()
                .map(|value| value.trim().to_owned())
                .map_err(|_| GatewayError::BadRequest {
                    message: format!("invalid header {name}"),
                })
        })
        .transpose()
        .map(|value| value.filter(|value| !value.is_empty()))
}

fn request_body_from_bytes(bytes: &[u8]) -> Result<Value> {
    if bytes.is_empty() {
        return Ok(json!({}));
    }
    serde_json::from_slice::<Value>(bytes).map_err(|error| GatewayError::BadRequest {
        message: format!("request body must be JSON: {error}"),
    })
}

fn requested_resource_id(body: &Value, path: &str) -> String {
    body.get("model")
        .and_then(Value::as_str)
        .filter(|model| !model.trim().is_empty())
        .map_or_else(|| resource_id_from_path(path), ToOwned::to_owned)
}

fn resource_id_from_path(path: &str) -> String {
    if let Some(rest) = path.strip_prefix("/v1beta/models/") {
        return rest
            .split(':')
            .next()
            .filter(|model| !model.is_empty())
            .unwrap_or("unknown")
            .to_owned();
    }
    if let Some(rest) = path.strip_prefix("/model/") {
        return rest
            .split('/')
            .next()
            .filter(|model| !model.is_empty())
            .unwrap_or("unknown")
            .to_owned();
    }
    if let Some(rest) = path.strip_prefix("/native/") {
        return rest.replace('/', ":");
    }
    "unknown".to_owned()
}

#[derive(Clone, Debug, Eq, PartialEq)]
struct RuntimeRouteTarget {
    authorization_resource_id: String,
    upstream_model_id: String,
    provider_endpoint: Option<ProviderEndpoint>,
    upstream_credential_id: Option<String>,
    upstream_credential_snapshot: Option<RuntimeCredentialSnapshot>,
    pricing_sku_id: Option<String>,
    route_decision_id: Option<String>,
    selected_route: Option<SelectedRouteEvidence>,
    decision_request: Option<RouteDecisionRequest>,
}

#[derive(Clone, Debug, Eq, PartialEq)]
struct RuntimeCredentialSnapshot {
    credential_kind: String,
    secret_ref_id: String,
}

async fn runtime_route_target(
    state: &AppState,
    actor: &AuthenticatedActor,
    replay_case: &GatewayReplayCase,
    requested_model: &str,
    route_affinity_hash: Option<&str>,
) -> Result<RuntimeRouteTarget> {
    let Some(loaded_catalog) = latest_catalog_for_actor(state, actor).await? else {
        return Ok(RuntimeRouteTarget {
            authorization_resource_id: requested_model.to_owned(),
            upstream_model_id: requested_model.to_owned(),
            provider_endpoint: None,
            upstream_credential_id: None,
            upstream_credential_snapshot: None,
            pricing_sku_id: None,
            route_decision_id: None,
            selected_route: None,
            decision_request: None,
        });
    };
    let decision_request = RouteDecisionRequest {
        protocol_family: replay_case.protocol_family,
        alias_name: requested_model.to_owned(),
        config_snapshot_id: Some(loaded_catalog.snapshot_id.clone()),
        config_version: Some(loaded_catalog.version),
    };
    let plan = loaded_catalog
        .catalog
        .plan_runtime_route_with_hot_state(&RoutePlanRequest {
            actor,
            protocol_family: replay_case.protocol_family,
            alias_name: requested_model,
            streaming: replay_case.streaming,
            hot_state: state.route_hot_state(),
            config_version: Some(loaded_catalog.version),
            now: chrono::Utc::now(),
            route_affinity_hash,
        })
        .await?;
    match plan.outcome {
        RoutePlanOutcome::Selected(selection) => {
            let upstream_credential_snapshot =
                runtime_credential_snapshot(&loaded_catalog.catalog, &selection);
            selected_runtime_route_target(
                state,
                actor,
                decision_request,
                *selection,
                upstream_credential_snapshot,
                loaded_catalog.version,
                route_affinity_hash,
            )
            .await
        }
        RoutePlanOutcome::ProviderGrantDenied => {
            record_route_decision_evidence(
                state,
                RouteDecisionRecord::terminal(
                    actor,
                    decision_request,
                    RouteDecisionStatus::Blocked,
                    "provider_grant_denied",
                    plan.filtered_summary,
                    chrono::Utc::now(),
                ),
            )
            .await?;
            Err(GatewayError::Authorization {
                reason: "provider_grant_denied",
            })
        }
        RoutePlanOutcome::NoRoute => {
            record_route_decision_evidence(
                state,
                RouteDecisionRecord::terminal(
                    actor,
                    decision_request,
                    RouteDecisionStatus::NoRoute,
                    "no_eligible_model_target",
                    plan.filtered_summary,
                    chrono::Utc::now(),
                ),
            )
            .await?;
            Err(GatewayError::NoRoute {
                reason: "no_eligible_model_target",
            })
        }
    }
}

async fn selected_runtime_route_target(
    state: &AppState,
    actor: &AuthenticatedActor,
    decision_request: RouteDecisionRequest,
    selection: RouteSelection,
    upstream_credential_snapshot: Option<RuntimeCredentialSnapshot>,
    config_version: i64,
    route_affinity_hash: Option<&str>,
) -> Result<RuntimeRouteTarget> {
    let selected_evidence = SelectedRouteEvidence {
        model_alias_id: selection.model_alias_id.clone(),
        route_policy_id: selection.route_policy_id.clone(),
        routing_group_id: selection.routing_group_id.clone(),
        model_target_id: selection.model_target_id.clone(),
        provider_endpoint_id: selection.provider_endpoint.provider_endpoint_id.clone(),
        upstream_credential_id: selection.upstream_credential_id.clone(),
        filtered_summary: selection.filtered_summary.clone(),
        sticky_hit: selection.sticky_hit,
        sticky_miss_reason: selection.sticky_miss_reason.clone(),
    };
    let decision = RouteDecisionRecord::selected(
        actor,
        decision_request.clone(),
        selected_evidence.clone(),
        chrono::Utc::now(),
    );
    let route_decision_id = decision.route_decision_id.clone();
    record_route_decision_evidence(state, decision).await?;
    record_sticky_route_mapping(
        state,
        actor,
        &selection,
        config_version,
        route_affinity_hash,
    )
    .await;
    Ok(RuntimeRouteTarget {
        authorization_resource_id: selection.model_alias_id,
        upstream_model_id: selection.upstream_model_id,
        provider_endpoint: Some(selection.provider_endpoint),
        upstream_credential_id: selection.upstream_credential_id,
        upstream_credential_snapshot,
        pricing_sku_id: selection.pricing_sku_id,
        route_decision_id: Some(route_decision_id),
        selected_route: Some(selected_evidence),
        decision_request: Some(decision_request),
    })
}

fn runtime_credential_snapshot(
    catalog: &GatewayCatalogSnapshot,
    selection: &RouteSelection,
) -> Option<RuntimeCredentialSnapshot> {
    selection.upstream_credential_id.as_deref().and_then(|id| {
        catalog
            .upstream_credentials
            .iter()
            .find(|credential| credential.upstream_credential_id == id)
            .map(|credential| RuntimeCredentialSnapshot {
                credential_kind: credential.credential_kind.clone(),
                secret_ref_id: credential.secret_ref_id.clone(),
            })
    })
}

async fn record_sticky_route_mapping(
    state: &AppState,
    actor: &AuthenticatedActor,
    selection: &RouteSelection,
    config_version: i64,
    route_affinity_hash: Option<&str>,
) {
    let Some(affinity_hash) = route_affinity_hash else {
        return;
    };
    let Some(ttl_seconds) = selection.sticky_ttl_seconds else {
        return;
    };
    let now = chrono::Utc::now();
    state
        .route_hot_state()
        .set_sticky_route(StickyRouteRecord {
            tenant_id: actor.tenant_id.clone(),
            project_id: actor.project_id.clone(),
            model_alias_id: selection.model_alias_id.clone(),
            affinity_hash: affinity_hash.to_owned(),
            routing_group_id: selection.routing_group_id.clone(),
            model_target_id: selection.model_target_id.clone(),
            provider_endpoint_id: selection.provider_endpoint.provider_endpoint_id.clone(),
            config_version,
            created_at: now,
            expires_at: now + chrono::Duration::seconds(ttl_seconds),
        })
        .await;
}

#[derive(Clone, Debug, Eq, PartialEq)]
struct LoadedCatalog {
    catalog: GatewayCatalogSnapshot,
    snapshot_id: String,
    version: i64,
}

async fn latest_catalog_for_actor(
    state: &AppState,
    actor: &AuthenticatedActor,
) -> Result<Option<LoadedCatalog>> {
    let Some(snapshot) = latest_snapshot_for_actor(state, actor).await? else {
        return Ok(None);
    };
    GatewayCatalogSnapshot::from_payload(&snapshot.document.payload).map(|catalog| {
        catalog.map(|catalog| LoadedCatalog {
            catalog,
            snapshot_id: snapshot.metadata.snapshot_id,
            version: snapshot.metadata.version,
        })
    })
}

async fn latest_snapshot_for_actor(
    state: &AppState,
    actor: &AuthenticatedActor,
) -> Result<Option<crate::config::PublishedConfigSnapshot>> {
    if let Some(store) = state.postgres_store.as_ref() {
        let Some(metadata) = store
            .latest_published_snapshot_for_tenant(&actor.tenant_id)
            .await?
        else {
            return Ok(None);
        };
        let snapshot = store
            .config_snapshot_by_id(&metadata.snapshot_id)
            .await?
            .ok_or_else(|| GatewayError::Internal {
                message: format!(
                    "latest config snapshot {} is missing from PostgreSQL",
                    metadata.snapshot_id
                ),
            })?;
        return Ok(Some(snapshot));
    }
    latest_snapshot_for_actor_in_memory(state, actor)
}

async fn latest_published_snapshot_for_readiness(
    state: &AppState,
) -> Result<Option<ConfigSnapshot>> {
    if let Some(store) = state.postgres_store.as_ref() {
        return store.latest_published_snapshot().await;
    }
    Ok(state.store.latest_published_snapshot())
}

async fn config_snapshots_for_actor(
    state: &AppState,
    actor: &AuthenticatedActor,
) -> Result<Vec<crate::config::PublishedConfigSnapshot>> {
    if let Some(store) = state.postgres_store.as_ref() {
        return store
            .config_snapshots_for_tenant(&actor.tenant_id, CONFIG_SNAPSHOT_DURABLE_SCAN_LIMIT)
            .await;
    }
    Ok(state
        .store
        .config_snapshots()
        .into_iter()
        .filter(|snapshot| snapshot.metadata.tenant_id == actor.tenant_id)
        .collect())
}

async fn config_snapshot_for_actor(
    state: &AppState,
    actor: &AuthenticatedActor,
    snapshot_id: &str,
) -> Result<crate::config::PublishedConfigSnapshot> {
    if let Some(store) = state.postgres_store.as_ref() {
        return store
            .config_snapshot_by_id(snapshot_id)
            .await?
            .filter(|snapshot| snapshot.metadata.tenant_id == actor.tenant_id)
            .ok_or_else(|| GatewayError::NotFound {
                resource: format!("config snapshot {snapshot_id}"),
            });
    }
    state
        .store
        .config_snapshot(snapshot_id)
        .filter(|snapshot| snapshot.metadata.tenant_id == actor.tenant_id)
        .ok_or_else(|| GatewayError::NotFound {
            resource: format!("config snapshot {snapshot_id}"),
        })
}

fn latest_snapshot_for_actor_in_memory(
    state: &AppState,
    actor: &AuthenticatedActor,
) -> Result<Option<crate::config::PublishedConfigSnapshot>> {
    let Some(metadata) = state
        .store
        .latest_published_snapshot_for_tenant(&actor.tenant_id)
    else {
        return Ok(None);
    };
    let snapshot = state
        .store
        .config_snapshot(&metadata.snapshot_id)
        .ok_or_else(|| GatewayError::Internal {
            message: format!(
                "latest config snapshot {} is missing from store",
                metadata.snapshot_id
            ),
        })?;
    Ok(Some(snapshot))
}

