    fn with_unset_env<R>(keys: &[&'static str], f: impl FnOnce() -> R) -> R {
        temp_env::with_vars_unset(keys, f)
    }

    fn with_env<R>(values: &[(&'static str, &'static str)], f: impl FnOnce() -> R) -> R {
        let vars = values
            .iter()
            .map(|(key, value)| (*key, Some(*value)))
            .collect::<Vec<_>>();
        temp_env::with_vars(vars, f)
    }

    #[tokio::test]
