    #[tokio::test]
    async fn api_prefix_exposes_system_probes_and_public_auth_discovery() {
        let health = match router(AppState::default())
            .oneshot(
                Request::builder()
                    .uri("/api/system/healthz")
                    .body(Body::empty())
                    .unwrap_or_else(|error| panic!("request should build: {error}")),
            )
            .await
        {
            Ok(response) => response,
            Err(error) => panic!("prefixed health request should complete: {error}"),
        };
        assert_eq!(health.status(), StatusCode::OK);
        assert_eq!(response_json(health).await["schema"], "gateway.health.v1");

        let providers = match router(AppState::default())
            .oneshot(
                Request::builder()
                    .uri("/api/auth/v1/providers")
                    .body(Body::empty())
                    .unwrap_or_else(|error| panic!("request should build: {error}")),
            )
            .await
        {
            Ok(response) => response,
            Err(error) => panic!("prefixed auth discovery should complete: {error}"),
        };
        let status = providers.status();
        let body = response_json(providers).await;
        assert_eq!(status, StatusCode::OK);
        assert_eq!(body["schema"], "gateway.auth.provider_list.v1");
    }

    #[tokio::test]
    async fn api_prefix_unknown_paths_return_json_errors() {
        let response = match router(AppState::default())
            .oneshot(
                Request::builder()
                    .uri("/api/not-a-real-route")
                    .body(Body::empty())
                    .unwrap_or_else(|error| panic!("request should build: {error}")),
            )
            .await
        {
            Ok(response) => response,
            Err(error) => panic!("unknown api request should complete: {error}"),
        };
        let status = response.status();
        let body = response_json(response).await;
        assert_eq!(status, StatusCode::NOT_FOUND);
        assert_eq!(body["schema"], "gateway.error.v1");
        assert_eq!(body["error"]["code"], "gateway.resource.not_found");
    }

    #[tokio::test]
    async fn api_prefix_exposes_external_openapi_contract() {
        let response = match router(AppState::default())
            .oneshot(
                Request::builder()
                    .uri("/api/openapi.json")
                    .body(Body::empty())
                    .unwrap_or_else(|error| panic!("request should build: {error}")),
            )
            .await
        {
            Ok(response) => response,
            Err(error) => panic!("prefixed OpenAPI request should complete: {error}"),
        };
        let status = response.status();
        let body = response_json(response).await;
        let paths = body["paths"]
            .as_object()
            .unwrap_or_else(|| panic!("OpenAPI paths should be an object"));

        assert_eq!(status, StatusCode::OK);
        assert_eq!(body["openapi"], "3.1.0");
        assert!(paths.contains_key("/api/v1/responses"));
        assert!(!paths.contains_key("/v1/responses"));
        assert_eq!(
            body["paths"]["/api/v1/responses"]["post"]["x-starweaver-canonical-path"],
            "/v1/responses"
        );
    }

    #[test]
    #[allow(clippy::too_many_lines)]
    fn gateway_config_from_env_enables_single_user_only_with_required_credentials() {
        const KEYS: &[&str] = &[
            "STARWEAVER_GATEWAY_DATABASE_URL",
            "STARWEAVER_GATEWAY_REDIS_URL",
            "STARWEAVER_GATEWAY_HOT_STATE_BACKEND",
            "STARWEAVER_GATEWAY_RUNTIME_STORE",
            "STARWEAVER_GATEWAY_ENV",
            "STARWEAVER_GATEWAY_DEPENDENCY_PROBE_MODE",
            "STARWEAVER_GATEWAY_READINESS_PROBE_TIMEOUT_MS",
            "STARWEAVER_GATEWAY_PUBLIC_BASE_URL",
            "STARWEAVER_GATEWAY_CORS_ALLOWED_ORIGINS",
            "STARWEAVER_GATEWAY_SESSION_COOKIE_SECURE",
            "STARWEAVER_GATEWAY_SESSION_COOKIE_HTTP_ONLY",
            "STARWEAVER_GATEWAY_SESSION_COOKIE_SAME_SITE",
            "STARWEAVER_GATEWAY_SINGLE_USER_USERNAME",
            "STARWEAVER_GATEWAY_SINGLE_USER_PASSWORD",
            "STARWEAVER_GATEWAY_SINGLE_USER_EMAIL",
            "STARWEAVER_GATEWAY_SINGLE_USER_DISPLAY_NAME",
            "STARWEAVER_GATEWAY_SINGLE_USER_SESSION_TTL_SECONDS",
            "STARWEAVER_GATEWAY_EXPORT_OBJECT_STORAGE_DIR",
            "STARWEAVER_GATEWAY_EXPORT_OBJECT_STORAGE_URL",
            "STARWEAVER_GATEWAY_EXPORT_OBJECT_STORAGE_AUTHORIZATION",
            "STARWEAVER_GATEWAY_EXPORT_OBJECT_STORAGE_TIMEOUT_SECONDS",
            "STARWEAVER_GATEWAY_BACKGROUND_WORKERS",
            "STARWEAVER_GATEWAY_WORKER_ID",
            "STARWEAVER_GATEWAY_WORKER_TICK_INTERVAL_SECONDS",
            "STARWEAVER_GATEWAY_NOTIFICATION_WORKER_BATCH_LIMIT",
        ];

        let _lock = ENV_TEST_MUTEX
            .lock()
            .unwrap_or_else(std::sync::PoisonError::into_inner);
        let export_dir = std::env::temp_dir().join("starweaver-gateway-exports");
        let export_dir_text = export_dir.to_string_lossy().to_string();
        with_unset_env(KEYS, || {
            assert!(GatewayConfig::from_env().single_user_auth.is_none());

            with_env(
                &[("STARWEAVER_GATEWAY_SINGLE_USER_USERNAME", "admin")],
                || {
                    assert!(GatewayConfig::from_env().single_user_auth.is_none());
                },
            );
            with_env(
                &[
                    ("STARWEAVER_GATEWAY_SINGLE_USER_USERNAME", "admin"),
                    ("STARWEAVER_GATEWAY_SINGLE_USER_PASSWORD", " "),
                ],
                || {
                    assert!(GatewayConfig::from_env().single_user_auth.is_none());
                },
            );
            with_env(
                &[
                    ("STARWEAVER_GATEWAY_SINGLE_USER_USERNAME", " "),
                    ("STARWEAVER_GATEWAY_SINGLE_USER_PASSWORD", "secret"),
                ],
                || {
                    assert!(GatewayConfig::from_env().single_user_auth.is_none());
                },
            );

            let vars = vec![
                ("STARWEAVER_GATEWAY_SINGLE_USER_USERNAME", Some(" admin ")),
                ("STARWEAVER_GATEWAY_SINGLE_USER_PASSWORD", Some(" secret ")),
                (
                    "STARWEAVER_GATEWAY_SINGLE_USER_EMAIL",
                    Some(" admin@example.com "),
                ),
                (
                    "STARWEAVER_GATEWAY_SINGLE_USER_DISPLAY_NAME",
                    Some(" Admin "),
                ),
                (
                    "STARWEAVER_GATEWAY_SINGLE_USER_SESSION_TTL_SECONDS",
                    Some("600"),
                ),
                (
                    "STARWEAVER_GATEWAY_EXPORT_OBJECT_STORAGE_DIR",
                    Some(export_dir_text.as_str()),
                ),
            ];
            temp_env::with_vars(vars, || {
                let config = GatewayConfig::from_env();
                let single_user = config
                    .single_user_auth
                    .unwrap_or_else(|| panic!("single-user config should be enabled"));

                assert_eq!(single_user.username, "admin");
                assert_eq!(single_user.password, "secret");
                assert_eq!(
                    config.dependency_probe_mode,
                    DependencyProbeMode::Configured
                );
                assert_eq!(config.hot_state_backend_profile, "memory");
                assert_eq!(config.runtime_store_profile, "memory");
                assert_eq!(
                    single_user.user_primary_email.as_deref(),
                    Some("admin@example.com")
                );
                assert_eq!(single_user.user_display_name, "Admin");
                assert_eq!(single_user.session_ttl_seconds, 600);
                assert_eq!(
                    config.export_object_storage_dir.as_deref(),
                    Some(export_dir_text.as_str())
                );
            });
        });
    }

