    #[tokio::test]
    async fn notification_delivery_respects_batch_limit_and_created_order() {
        let (store, raw_session) = gateway_store_with_admin_session();
        let notification_sink_id =
            create_stdout_notification_sink_over_http(store.clone(), &raw_session).await;
        let base = chrono::Utc::now() - Duration::seconds(10);
        let append_event = |dedupe_key: &str, created_at| {
            store
                .append_notification_outbox_event(
                    CreateNotificationOutboxEventRequest {
                        tenant_id: TEST_TENANT_ID.to_owned(),
                        organization_id: Some(TEST_ORGANIZATION_ID.to_owned()),
                        project_id: Some(TEST_PROJECT_ID.to_owned()),
                        notification_subscription_id: None,
                        notification_sink_id: Some(notification_sink_id.clone()),
                        event_kind: "gateway.delivery.synthetic".to_owned(),
                        dedupe_key: dedupe_key.to_owned(),
                        payload_document: json!({
                            "schema": "gateway.notification.synthetic.v1",
                            "redaction": {
                                "request_body_included": false,
                                "provider_body_included": false
                            },
                            "event": {"kind": dedupe_key}
                        }),
                        next_attempt_at: Some(base),
                    },
                    created_at,
                )
                .notification_outbox_event_id
        };

        let first_id = append_event("notification_batch_first", base);
        let second_id = append_event("notification_batch_second", base + Duration::seconds(1));
        let third_id = append_event("notification_batch_third", base + Duration::seconds(2));

        let first_batch = deliver_due_notifications(
            &AppState::new(GatewayConfig::default(), store.clone()),
            TEST_TENANT_ID,
            base + Duration::seconds(3),
            2,
        )
        .await;
        let first_event = store
            .notification_outbox_event(&first_id)
            .unwrap_or_else(|| panic!("first notification event should remain stored"));
        let second_event = store
            .notification_outbox_event(&second_id)
            .unwrap_or_else(|| panic!("second notification event should remain stored"));
        let third_event = store
            .notification_outbox_event(&third_id)
            .unwrap_or_else(|| panic!("third notification event should remain stored"));

        assert_eq!(first_batch.len(), 2);
        assert_eq!(first_batch[0].notification_outbox_event_id, first_id);
        assert_eq!(first_batch[1].notification_outbox_event_id, second_id);
        assert_eq!(first_event.status, "delivered");
        assert_eq!(second_event.status, "delivered");
        assert_eq!(third_event.status, "pending");
        assert_eq!(third_event.attempt_count, 0);

        let second_batch = deliver_due_notifications(
            &AppState::new(GatewayConfig::default(), store.clone()),
            TEST_TENANT_ID,
            base + Duration::seconds(4),
            10,
        )
        .await;
        let third_delivered = store
            .notification_outbox_event(&third_id)
            .unwrap_or_else(|| panic!("third notification event should remain stored"));

        assert_eq!(second_batch.len(), 1);
        assert_eq!(second_batch[0].notification_outbox_event_id, third_id);
        assert_eq!(third_delivered.status, "delivered");
        assert_eq!(third_delivered.attempt_count, 1);
    }

    #[tokio::test]
    async fn notification_webhook_delivery_signs_payload_and_uses_rotated_secret() {
        let (store, raw_session) = gateway_store_with_admin_session();
        let notification_sink_id =
            create_notification_sink_over_http(store.clone(), &raw_session).await;
        let first_signing_secret_ref_id = store
            .notification_sink(&notification_sink_id)
            .and_then(|sink| sink.signing_secret_ref_id)
            .unwrap_or_else(|| panic!("notification sink should have signing secret"));
        let first_event_id = append_synthetic_notification_event(
            &store,
            &notification_sink_id,
            "notification_webhook_delivery_first",
            "synthetic",
        );
        let first_attempt = deliver_first_due_notification(store.clone(), chrono::Utc::now()).await;
        let first_signature_sha256 = assert_signed_webhook_attempt(
            &first_attempt,
            &first_event_id,
            &first_signing_secret_ref_id,
        );
        let rotated_signing_secret_ref_id = create_secret_ref_over_http(
            store.clone(),
            &raw_session,
            "notification-webhook-rotated-secret-value",
        )
        .await;
        rotate_notification_sink_signing_secret(
            store.clone(),
            &raw_session,
            &notification_sink_id,
            &rotated_signing_secret_ref_id,
        )
        .await;
        let rotated_event_id = append_synthetic_notification_event(
            &store,
            &notification_sink_id,
            "notification_webhook_delivery_rotated",
            "rotated",
        );
        let rotated_attempt = deliver_first_due_notification(
            store.clone(),
            chrono::Utc::now() + Duration::seconds(1),
        )
        .await;
        let rotated_signature_sha256 = assert_signed_webhook_attempt(
            &rotated_attempt,
            &rotated_event_id,
            &rotated_signing_secret_ref_id,
        );

        assert_ne!(rotated_signature_sha256, first_signature_sha256);
        let audit_text = serde_json::to_string(&store.audit_events())
            .unwrap_or_else(|error| panic!("audit events should serialize: {error}"));
        assert!(!audit_text.contains("notification-webhook-rotated-secret-value"));
        assert!(store.audit_events().iter().any(|event| {
            event.event_type == "gateway.notification_sink.update"
                && event.redacted_diff["signing_secret_ref_id"]["after"] == "sec_***"
        }));
    }

    #[tokio::test]
    async fn notification_webhook_delivery_posts_to_local_http_receiver() {
        let (store, raw_session) = gateway_store_with_admin_session();
        let (webhook_url, captured_requests, server_handle) =
            spawn_local_webhook_receiver(StatusCode::NO_CONTENT).await;
        let signing_secret = "notification-webhook-local-secret-value";
        let signing_secret_ref_id = seed_secret_ref_for_test(
            &store,
            Some(TEST_ORGANIZATION_ID),
            Some(TEST_PROJECT_ID),
            "notification webhook signing",
            signing_secret,
        );
        let notification_sink_id = create_local_http_notification_sink_over_http(
            store.clone(),
            &raw_session,
            &webhook_url,
            &signing_secret_ref_id,
        )
        .await;
        let event_id = append_synthetic_notification_event(
            &store,
            &notification_sink_id,
            "notification_webhook_delivery_real_http",
            "real_http",
        );

        let attempts = deliver_due_notifications(
            &AppState::new(GatewayConfig::default(), store.clone()),
            TEST_TENANT_ID,
            chrono::Utc::now(),
            10,
        )
        .await;
        let captured = captured_requests
            .recv_timeout(std::time::Duration::from_secs(2))
            .unwrap_or_else(|error| panic!("webhook receiver should capture request: {error}"));
        server_handle.abort();
        let delivered = store
            .notification_outbox_event(&event_id)
            .unwrap_or_else(|| panic!("delivered event should remain stored"));
        let body = assert_captured_webhook_request(&captured, &event_id, signing_secret);
        let delivery_headers = attempts[0].delivery_headers.to_string();

        assert_eq!(attempts.len(), 1);
        assert_eq!(attempts[0].notification_outbox_event_id, event_id);
        assert_eq!(attempts[0].status, "succeeded");
        assert_eq!(attempts[0].response_status, Some(204));
        assert_eq!(
            attempts[0].signing_secret_ref_id.as_deref(),
            Some(signing_secret_ref_id.as_str())
        );
        assert_eq!(delivered.status, "delivered");
        assert_eq!(delivered.attempt_count, 1);
        assert_eq!(body["event"]["kind"], "real_http");
        assert!(delivery_headers.contains("\"transport_mode\":\"http\""));
        assert!(delivery_headers.contains("\"response_status_class\":\"2xx\""));
        assert!(!delivery_headers.contains(signing_secret));
        assert!(!delivery_headers.contains("\"event\""));
    }

